    numbers = re.findall(r'-?\d+', line)
    if len(numbers) < 2:
        return 'INVALID'
    N = int(numbers[0])
    M = int(numbers[1])
    if 'apples' in line:
        return N + M
    elif 'candies' in line:
        if M > N:
            return 'INVALID'
        return N - M
    elif 'marbles' in line:
        if M > N:
            return 'INVALID'
        return N - M
    return 'INVALID'

